+  let commitSha = '';
+  let checkpointId = '';
+  let workspaceId = '';
+  let deploymentId = '';
+  let reviewId = '';
+  let reviewResultUrl = '';
+
+  try {
+    spinner.start('Resolving checkpoint...');
+    try {
+      const resolved = resolveReviewCommitContext(commitish);
+      commitSha = resolved.commitSha;
