+      }
+      spinner.stop(`Resolved checkpoint ${checkpointId} from ${commitSha.slice(0, 12)}`);
+    } catch (error) {
+      const message = error instanceof Error ? error.message : String(error);
+      spinner.stop('Checkpoint resolution failed');
